fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val graph = mutableListOf<MutableList<Long>>().also { it.resize(n.toInt()) }
    for (i in edges.indices) {
        val u = edges[i][0].toInt()
        val v = edges[i][1].toInt()
        val s = edges[i][2]
        val e = edges[i][3]
        graph[u].add(v)
        graph[u].add(s)
        graph[u].add(e)
    }

    val pq = PriorityQueue<MutableList<Long>>(compareBy { it[0] })
    pq.add(arrayOf(0L, 0L))
    val visited = mutableMapOf<Long, Long>()

    while (pq.isNotEmpty()) {
        val currentTime = pq.peek()[0]
        val currentNode = pq.peek()[1]
        pq.poll()

        if (currentNode == n - 1) {
            return currentTime
        }

        if (visited.containsKey(currentNode) && visited[currentNode]!! <= currentTime) {
            continue
        }
        visited[currentNode] = currentTime

        for (i in graph[currentNode.toInt()].indices step 2) {
            val neighbor = graph[currentNode.toInt()][i]
            val start = graph[currentNode.toInt()][i + 1]
            val end = graph[currentNode.toInt()][i + 2]

            if (start <= currentTime && currentTime <= end) {
                val newTime = currentTime + 1
                if (!visited.containsKey(neighbor) || newTime < visited[neighbor]!!) {
                    pq.add(arrayOf(newTime, neighbor))
                }
            } else {
                val waitTime = start - currentTime
                val newTime = start + 1
                if (!visited.containsKey(neighbor) || newTime < visited[neighbor]!!) {
                    pq.add(arrayOf(newTime, neighbor))
                }
            }
        }
    }

    return -1
}
